using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleItems_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-002", 1, 12.50m);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 3, 10.00m);
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 5.00m);
        _cart.RemoveItem("SKU-001");
    }

    [TestMethod]
    public void RemoveItem_AfterRemoval_ItemNotInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);
        _cart.RemoveItem("SKU-001");

        var total = _cart.CalculateTotal();
        Assert.AreEqual(20.00m, total);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_DoesNotThrow()
    {
        // Depending on implementation, this may throw or be a no-op.
        // Adjust expectation once implemented.
        _cart.RemoveItem("NONEXISTENT");
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var total = _cart.CalculateTotal();
        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 3, 4.00m);

        var total = _cart.CalculateTotal();
        Assert.AreEqual(12.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-002", 1, 7.50m);

        var total = _cart.CalculateTotal();
        Assert.AreEqual(17.50m, total);
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected total less than 100, got {total}");
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_DoesNotThrow()
    {
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon("INVALIDCODE");
    }

    // --- Integration / Combined Tests ---

    [TestMethod]
    public void AddThenRemoveThenTotal_ReflectsCorrectState()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 2, 15.00m);
        _cart.RemoveItem("SKU-001");

        var total = _cart.CalculateTotal();
        Assert.AreEqual(30.00m, total);
    }

    [TestMethod]
    public void FullWorkflow_AddItemsApplyCouponCalculateTotal()
    {
        _cart.AddItem("SKU-001", 2, 25.00m);
        _cart.AddItem("SKU-002", 1, 50.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        // 2*25 + 50 = 100; after coupon the total should be discounted
        Assert.IsTrue(total < 100.00m, $"Expected discounted total, got {total}");
    }
}

